76	export async function triggerCatalogSync() {
77	  if (activeSync) {
78	    syncState.lastTriggeredAt = new Date().toISOString();
79	    return { started: false };
80	  }
81	
82	  syncState.isSyncing = true;
83	  syncState.lastStartedAt = new Date().toISOString();
84	  syncState.lastTriggeredAt = syncState.lastStartedAt;
85	
86	  activeSync = (async () => {
87	    try {
88	      await applyLatestCatalogData();
89	      syncState.lastCompletedAt = new Date().toISOString();
90	      revalidateTag('products', 'max');
91	    } finally {
92	      syncState.isSyncing = false;
93	      activeSync = null;
94	    }
95	  })();
96	
97	  return { started: true };
